// package-lock.json generation script (run via npm or yarn)
const fs = require('fs');
const path = require('path');
const yargs = require('yargs');

// Command-line options
yargs.command({
  command: 'generate-lock',
  describe: 'Generate a new package-lock.json file based on existing yarn.lock/npm-shrinkwrap.json'
})
    .option('verbose', {
      type: 'boolean',
      describe: 'Enable verbose mode for debugging'
    })
    .demandCommand()
    .help()
    .alias('h', 'help')
    .parse(process.argv);

const generateLockFile = () => {
  try {
    // Determine the current package manager
    const shrinkwrapPath = path.resolve('npm-shrinkwrap.json');
    const yarnlockPath = path.resolve('yarn.lock');

    let lockFilePath;
    if (fs.existsSync(shrinkwrapPath)) {
      lockFilePath = shrinkwrapPath;
    } else if (fs.existsSync(yarnlockPath)) {
      lockFilePath = yarnlockPath;
    } else {
      throw new Error('Neither npm-shrinkwrap.json nor yarn.lock exists');
    }

    // Copy and transform the lock file
    const contents = fs.readFileSync(lockFilePath, 'utf8').replace(/npm-shrinkwrap\.json:/gm, '');
    fs.writeFileSync(path.resolve('package-lock.json'), contents);
  } catch (err) {
    console.error(err.message);
  }
};

if (yargs.command() === 'generate-lock') {
  generateLockFile();
}